# Render at 4x for quality, then downscale
png = cairosvg.svg2png(bytestring=svg.encode(), output_width=128, output_height=86)
big = Image.open(io.BytesIO(png)).convert('RGBA')

# Downscale to 30x20 (fits in 32x32 with 1px padding each side)
sprite = big.resize((30, 20), Image.LANCZOS)

# Place on 32x32 canvas centered
canvas = Image.new('RGBA', (32, 32), (0, 0, 0, 0))
canvas.paste(sprite, (1, 6), sprite)
canvas.save('/home/tidabit1977/butterfly_sprite.png')
print('saved butterfly_sprite.png')

# Show pixel stats
arr = list(canvas.getdata())
white = sum(1 for r,g,b,a in arr if a > 128)
print(f'{white} opaque pixels out of 1024')
